225	func updateResourceRequirements(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
226		resources := trustManager.Spec.TrustManagerConfig.Resources
227		if len(resources.Limits) == 0 && len(resources.Requests) == 0 {
228			return nil
229		}
230		if err := common.ValidateResourceRequirements(resources, trustManagerConfigFieldPath); err != nil {
231			return err
232		}
233		for i := range deployment.Spec.Template.Spec.Containers {
234			if deployment.Spec.Template.Spec.Containers[i].Name == trustManagerContainerName {
235				deployment.Spec.Template.Spec.Containers[i].Resources = resources
236			}
237		}
238		return nil
239	}
240	
241	func updateAffinityRules(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
242		if trustManager.Spec.TrustManagerConfig.Affinity == nil {
243			return nil
244		}
245		if err := common.ValidateAffinityRules(trustManager.Spec.TrustManagerConfig.Affinity, trustManagerConfigFieldPath); err != nil {
246			return err
247		}
248		deployment.Spec.Template.Spec.Affinity = trustManager.Spec.TrustManagerConfig.Affinity
249		return nil
250	}
251	
252	func updatePodTolerations(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
253		if trustManager.Spec.TrustManagerConfig.Tolerations == nil {
254			return nil
255		}
256		if err := common.ValidateTolerationsConfig(trustManager.Spec.TrustManagerConfig.Tolerations, trustManagerConfigFieldPath); err != nil {
257			return err
258		}
259		deployment.Spec.Template.Spec.Tolerations = trustManager.Spec.TrustManagerConfig.Tolerations
260		return nil
261	}
262	
263	func updateNodeSelector(deployment *appsv1.Deployment, trustManager *v1alpha1.TrustManager) error {
264		if trustManager.Spec.TrustManagerConfig.NodeSelector == nil {
265			return nil
266		}
267		if err := common.ValidateNodeSelectorConfig(trustManager.Spec.TrustManagerConfig.NodeSelector, trustManagerConfigFieldPath); err != nil {
268			return err
269		}
270		if deployment.Spec.Template.Spec.NodeSelector == nil {
271			deployment.Spec.Template.Spec.NodeSelector = make(map[string]string)
272		}
273		// Merge user-specified node selectors with any default selectors from the manifest.
274		// User-specified selectors take precedence.
275		for k, v := range trustManager.Spec.TrustManagerConfig.NodeSelector {
276			deployment.Spec.Template.Spec.NodeSelector[k] = v
277		}
278		return nil
279	}
280	
281	func updateServiceAccountName(deployment *appsv1.Deployment) {
282		deployment.Spec.Template.Spec.ServiceAccountName = trustManagerServiceAccountName
283	}
284	
285	const tlsVolumeName = "tls"
286	
287	func updateTLSSecretVolume(deployment *appsv1.Deployment) {
288		for i, vol := range deployment.Spec.Template.Spec.Volumes {
289			if vol.Name == tlsVolumeName && vol.Secret != nil {
290				deployment.Spec.Template.Spec.Volumes[i].Secret.SecretName = trustManagerTLSSecretName
291				return
292			}
293		}
294	}
