4	
5	import (
6		context "context"
7		time "time"
8	
9		apiconfigv1 "github.com/openshift/api/config/v1"
10		versioned "github.com/openshift/client-go/config/clientset/versioned"
11		internalinterfaces "github.com/openshift/client-go/config/informers/externalversions/internalinterfaces"
12		configv1 "github.com/openshift/client-go/config/listers/config/v1"
13		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
14		runtime "k8s.io/apimachinery/pkg/runtime"
15		watch "k8s.io/apimachinery/pkg/watch"
16		cache "k8s.io/client-go/tools/cache"
17	)
18	
19	// ProxyInformer provides access to a shared informer and lister for
20	// Proxies.
21	type ProxyInformer interface {
22		Informer() cache.SharedIndexInformer
23		Lister() configv1.ProxyLister
24	}
25	
26	type proxyInformer struct {
27		factory          internalinterfaces.SharedInformerFactory
28		tweakListOptions internalinterfaces.TweakListOptionsFunc
29	}
30	
31	// NewProxyInformer constructs a new informer for Proxy type.
32	// Always prefer using an informer factory to get a shared informer instead of getting an independent
33	// one. This reduces memory footprint and number of connections to the server.
34	func NewProxyInformer(client versioned.Interface, resyncPeriod time.Duration, indexers cache.Indexers) cache.SharedIndexInformer {
35		return NewFilteredProxyInformer(client, resyncPeriod, indexers, nil)
36	}
37	
38	// NewFilteredProxyInformer constructs a new informer for Proxy type.
39	// Always prefer using an informer factory to get a shared informer instead of getting an independent
40	// one. This reduces memory footprint and number of connections to the server.
41	func NewFilteredProxyInformer(client versioned.Interface, resyncPeriod time.Duration, indexers cache.Indexers, tweakListOptions internalinterfaces.TweakListOptionsFunc) cache.SharedIndexInformer {
42		return cache.NewSharedIndexInformer(
43			cache.ToListWatcherWithWatchListSemantics(&cache.ListWatch{
44				ListFunc: func(options metav1.ListOptions) (runtime.Object, error) {
45					if tweakListOptions != nil {
46						tweakListOptions(&options)
47					}
48					return client.ConfigV1().Proxies().List(context.Background(), options)
49				},
50				WatchFunc: func(options metav1.ListOptions) (watch.Interface, error) {
51					if tweakListOptions != nil {
52						tweakListOptions(&options)
53					}
54					return client.ConfigV1().Proxies().Watch(context.Background(), options)
55				},
56				ListWithContextFunc: func(ctx context.Context, options metav1.ListOptions) (runtime.Object, error) {
57					if tweakListOptions != nil {
58						tweakListOptions(&options)
59					}
60					return client.ConfigV1().Proxies().List(ctx, options)
61				},
62				WatchFuncWithContext: func(ctx context.Context, options metav1.ListOptions) (watch.Interface, error) {
63					if tweakListOptions != nil {
64						tweakListOptions(&options)
65					}
66					return client.ConfigV1().Proxies().Watch(ctx, options)
67				},
68			}, client),
69			&apiconfigv1.Proxy{},
70			resyncPeriod,
71			indexers,
72		)
73	}
74	
75	func (f *proxyInformer) defaultInformer(client versioned.Interface, resyncPeriod time.Duration) cache.SharedIndexInformer {
76		return NewFilteredProxyInformer(client, resyncPeriod, cache.Indexers{cache.NamespaceIndex: cache.MetaNamespaceIndexFunc}, f.tweakListOptions)
77	}
78	
79	func (f *proxyInformer) Informer() cache.SharedIndexInformer {
80		return f.factory.InformerFor(&apiconfigv1.Proxy{}, f.defaultInformer)
81	}
82	
83	func (f *proxyInformer) Lister() configv1.ProxyLister {
84		return configv1.NewProxyLister(f.Informer().GetIndexer())
85	}
