// applyProxyEnv sets HTTP_PROXY, HTTPS_PROXY and NO_PROXY environment variables
// on the trust-manager container from the cluster-wide proxy configuration.
func applyProxyEnv(deployment *appsv1.Deployment, proxyStatus *configv1.ProxyStatus) {
	if proxyStatus == nil {
		return
	}
	var envVars []corev1.EnvVar
	if proxyStatus.HTTPProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTP_PROXY", Value: proxyStatus.HTTPProxy})
	}
	if proxyStatus.HTTPSProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "HTTPS_PROXY", Value: proxyStatus.HTTPSProxy})
	}
	if proxyStatus.NoProxy != "" {
		envVars = append(envVars, corev1.EnvVar{Name: "NO_PROXY", Value: proxyStatus.NoProxy})
	}
	if len(envVars) == 0 {
		return
	}
	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Env = append(deployment.Spec.Template.Spec.Containers[i].Env, envVars...)
			break
		}
	}
}
